import Vue from 'vue'
import Router from 'vue-router'
import Home from './views/Home.vue'
import Login from './views/Login.vue'
import Profile from './views/Profile.vue'
import Users from './views/Users.vue'

import MarathonSurveyIndex from './views/marathon-survey/Index.vue'
import MarathonSurveyRunnerInformation from './views/marathon-survey/RunnerInformation.vue'
import MarathonSurveyRunnerReview from './views/marathon-survey/RunnerReview.vue'
import MarathonSurveyRunnerDetail from './views/marathon-survey/RunnerDetail.vue'
import EventIndex from './views/event/Index.vue'
import EventCreate from './views/event/Create.vue'
import EventUpdate from './views/event/Update.vue'

Vue.use (Router)

export default new Router ({
  routes: [
    {
      path: '/',
      name: 'home',
      component: Home,
    },
    {
      path: '/login',
      name: 'login',
      component: Login,
    },
    {
      path: '/users',
      name: 'users',
      component: Users,
    },
    {
      path: '/profile',
      name: 'profile',
      component: Profile,
    },
    {
      path: '/marathon-survey/index',
      name: 'marathon_survey_index',
      component: MarathonSurveyIndex,
    },
    {
      path: '/marathon-survey/runner-information',
      name: 'marathon_survey_runner_information',
      component: MarathonSurveyRunnerInformation,
    },
    {
      path: '/marathon-survey/runner-review',
      name: 'marathon_survey_runner_review',
      component: MarathonSurveyRunnerReview,
    },
    {
      path: '/marathon-survey/runner-detail/:id',
      name: 'marathon_survey_runner_detail',
      component: MarathonSurveyRunnerDetail,
    },
    {
      path: '/event/index',
      name: 'event_index',
      component: EventIndex,
    },
    {
      path: '/event/create',
      name: 'event_create',
      component: EventCreate,
    },
    {
      path: '/event/:id/update',
      name: 'event_update',
      component: EventUpdate,
    },
  ]
})
